DO $$ DECLARE v_lesson_id uuid; BEGIN
  SELECT id INTO v_lesson_id FROM lessons WHERE module_id = '9a681ce2-e300-404e-be2c-a081e6795ade' AND order_index = 3;
  IF v_lesson_id IS NULL THEN
    INSERT INTO lessons (course_id, module_id, institution_id, title, order_index, content_type, content_url, is_required)
    VALUES ('823fe330-1df4-42ee-89af-d7df079958f5', '9a681ce2-e300-404e-be2c-a081e6795ade', '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'Lesson 3: Fundraising', 3, 'blocks', '', true)
    RETURNING id INTO v_lesson_id;
  END IF;
  DELETE FROM lesson_blocks WHERE lesson_id = v_lesson_id;
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Fundraising', '{"html":"<p>Fundraising is the act of engaging in the organized activity of raising funds to support a cause, campaign, etc. </p>\n<img src=\"fit_content_assets/pikaso_texttoimage_35mm-film-photography-A-person-of-mixed-racial-des_m55wxj.jpg\" alt=\"\" />\n<p>There are many types of fundraising: <strong>Grants, Corporate Partnership, Peer-to-Peer, Capital Campaigns, Crowdfunding, Planned Giving, Direct Solicitation, </strong>and <strong>Events.</strong></p>","media":[{"type":"image","url":"fit_content_assets/pikaso_texttoimage_35mm-film-photography-A-person-of-mixed-racial-des_m55wxj.jpg"}],"mode":"scrolling"}'::jsonb, 0, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'image_gallery', '', '{"images":[{"url":"fit_content_assets/pikaso_reimagine_An-elderly-Caucasian-man-and-woman-in-formal-attir_ci0fg0.jpg","caption":"<p>Grants are a major source of funding for nonprofit organizations.</p>"},{"url":"fit_content_assets/pikaso_texttoimage_35mm-film-photography-Upbeat-volunteers-with-broad_dugzvb.jpg","caption":"<p>Fundable Programs are programs targeting awareness around a cause, the arts, educational initiatives, environmental protection, and much more (e.g. TASKOP Global Consulting provides ABC charitable organization with $50k in restricted grant to support their youth program).</p>"},{"url":"fit_content_assets/pikaso_reimagine_A-middleaged-Black-man-with-short-dark-hair-and-gl_uxeoht.jpg","caption":"<p><strong>Steps to Secure Grant Funding</strong></p><ol><li><p>Identify opportunities through grant-giving foundations, corporations, and government</p></li><li><p>Write and submit the grant proposals</p><p>Examples of Funding Platforms: Grant Connect &amp; Canada Grant Watch</p></li></ol>"}],"mode":"slider"}'::jsonb, 1, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Corporate Partnership', '{"html":"<p>A corporate partnership is where a charity forms a relationship with a business. It usually involves a charity receiving funds, goods or services in exchange for something the corporate partner sees as beneficial.</p>\n<img src=\"fit_content_assets/0001-5801065320622793044_oamp4v.png\" alt=\"\" />\n<p><strong>Benefits of Corporate Partnership</strong></p><ul><li><p>A source of increased volunteer and operating funds for charities</p></li></ul><ul><li><p>Improving the corporation''s community-wide reputation and trust</p></li></ul><p><strong>Tips on Success</strong></p><ul><li><p>Partner with corporations whose values align</p></li><li><p>Communication must be transparent and open between partners</p></li></ul>","media":[{"type":"image","url":"fit_content_assets/0001-5801065320622793044_oamp4v.png"}],"mode":"scrolling"}'::jsonb, 2, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'image_gallery', '', '{"images":[{"url":"fit_content_assets/pikaso_texttoimage_35mm-film-photography-Volunteers-with-bright-expre_obidgo.jpg","caption":"<p>Crowdfunding is the practice of raising money from a large number of people to fund a project or goal.</p><p>In 2015, over US$34B were raised worldwide by crowdfunding.</p>"},{"url":"fit_content_assets/pikaso_texttoimage_a-computer-screen-that-shows-a-progress-bar-with-t_paje5k.jpg","caption":"<p>Crowdfunding allows you to put out a call for donations that can quickly and easily attract donors that may give gifts of all sizes. If done well, crowdfunding has the opportunity to be viral.</p><p>Examples of crowdfunding online platforms include <strong>Kickstarter,\nGoFundMe, IndieGoGo etc.</strong></p>"}],"mode":"slider"}'::jsonb, 3, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'image_gallery', '', '{"images":[],"mode":"gallery"}'::jsonb, 4, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"segments":[],"mode":"sequence"}'::jsonb, 5, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Earned Income', '{"html":"<p>Earned income is the&nbsp;revenue generated from the sale of goods, services rendered, or work performed (e.g. the Girl Scouts'' cookie sales)</p>\n<img src=\"fit_content_assets/0001-6428191568335440976_pnzqxe.png\" alt=\"\" />\n<p>Earned income is gaining popularity among nonprofits especially with increasing competition for donor funds is causing income from grants and individual donations to level off. </p><p></p><p>Key–<strong>be creative!</strong></p><p></p><p>It provides organizations the opportunity to diversify or expand their base of funds to meet growing needs and to better sustain their operations over the long term.</p>","media":[{"type":"image","url":"fit_content_assets/0001-6428191568335440976_pnzqxe.png"}],"mode":"scrolling"}'::jsonb, 6, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'image_gallery', '', '{"images":[],"mode":"gallery"}'::jsonb, 7, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'image_gallery', '', '{"images":[{"url":"fit_content_assets/0001-8016836338790529676_ea0jhz.png","caption":"<p>Direct Mail Solicitation is the process of designing, writing, printing, and distributing hard copy requests for funds to your donors and/or prospective donors and this may be more effective in settings with reliable postage system.</p>"},{"url":"","caption":"<p><strong>Benefits of DMS</strong></p><ul><li><p>Direct mail builds trust more easily than online marketing</p></li><li><p>Direct mail has a higher response rate than email</p></li><li><p>Direct mail is more likely to get read or scanned in some parts of the world, limited people have access to the internet.</p></li></ul>"},{"url":"","caption":"<p><strong>Ways to Ensure Success of your Direct Mail Solicitation</strong></p><p>1. Know your audience</p><p>2. Tell a story that resonates with your audience.</p><p>3. Use varied media forms, set goals, and track progress</p>"}],"mode":"slider"}'::jsonb, 8, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Capital Campaigns', '{"html":"<p>A capital campaign is a fundraising effort for concrete projects\nsuch as new construction, acquisition or renovation of a building\nover a specific time period.</p>\n<img src=\"fit_content_assets/0001-1996649538205733740_hdxhde.png\" alt=\"\" />\n<p>Sometimes capital campaigns are used to build an endowment for the future or to purchase an extraordinary and expensive piece of equipment.</p>","media":[{"type":"image","url":"fit_content_assets/0001-1996649538205733740_hdxhde.png"}],"mode":"scrolling"}'::jsonb, 9, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'image_gallery', '', '{"images":[{"url":"fit_content_assets/pikaso_texttoimage_an-organization-meeting-with-donors-and-shaking-ha_lqnv5e.jpg","caption":"<p>A fundraising event is usually designed to raise awareness and support for an organization''s mission.</p>"},{"url":"fit_content_assets/0001-5600655136922303785_r1ti7i.png","caption":"<p>Any events including concerts, galas, live or silent auctions, half marathons, neighborhood cookouts, birthdays and anniversaries can be turned into fundraising events, or an opportunity to raise money.</p>"},{"url":"","caption":"<p><strong>Benefits of Fundraising Events</strong></p><p>Events allow the organizations to get face-to-face with donors, allowing them to reiterate their mission and discuss ways people can get more involved in their work.</p>"},{"url":"","caption":"<p><strong>Drawback of Fundraising Events</strong></p><p>Many special events often raise a small amount of net proceeds and require a large amount of time and energy to plan and implement.</p>"}],"mode":"slider"}'::jsonb, 10, true, 1, '{}'::jsonb);
